// ─── BroadcastChannel ─────────────────────────────────────────────
const CHANNEL = 'styleicon-slide-sync'

function useSyncSend() {
  const ch = useRef(null)
  const ready = useRef(false)
  useEffect(() => {
    ch.current = new BroadcastChannel(CHANNEL)
    ready.current = true
    return () => { ch.current.close(); ready.current = false }
  }, [])
  const send = useRef((id) => {
    if (ready.current) ch.current.postMessage({ sectionId: id })
    else setTimeout(() => ch.current?.postMessage({ sectionId: id }), 150)
  })
  return send.current
}

function useSyncReceive(onSection) {
  useEffect(() => {
    const ch = new BroadcastChannel(CHANNEL)
    ch.onmessage = (e) => { if (e.data?.sectionId) onSection(e.data.sectionId) }
    return () => ch.close()
  }, [onSection])
}

// ─── Timer ────────────────────────────────────────────────────────
function useElapsedTimer() {
  const [elapsed, setElapsed] = useState(0)
  const startRef = useRef(Date.now())
  useEffect(() => {
    const t = setInterval(() => setElapsed(Math.floor((Date.now() - startRef.current) / 1000)), 1000)
    return () => clearInterval(t)
  }, [])
  const mm = String(Math.floor(elapsed / 60)).padStart(2, '0')
  const ss = String(elapsed % 60).padStart(2, '0')
  return { time: `${mm}:${ss}`, over: elapsed > 1200 }
}

// ─── IntersectionObserver fade-in ─────────────────────────────────
function useFadeIn() {
  useEffect(() => {
    const obs = new IntersectionObserver(
      entries => entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.style.opacity = '1'
          e.target.style.transform = 'translateY(0)'
        }
      }),
      { threshold: 0.07 }
    )
    document.querySelectorAll('.fi').forEach(el => obs.observe(el))
    return () => obs.disconnect()
  }, [])
}

const fiStyle = { opacity: 0, transform: 'translateY(40px)', transition: 'opacity 0.9s ease, transform 0.9s ease' }

// ─── Three.js hook ─────────────────────────────────────────────────
function useThreeScene(initFn) {
  const mountRef = useRef(null)
  useEffect(() => {
    const mount = mountRef.current
    if (!mount) return
    let cleanup = null, animId = null

    const start = () => {
      const w = mount.clientWidth, h = mount.clientHeight
      if (w === 0 || h === 0) return
      const canvas = document.createElement('canvas')
      canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;display:block;'
      mount.appendChild(canvas)
      try {
        cleanup = initFn(canvas, w, h, (id) => { animId = id })
      } catch (e) {
        console.error(e); canvas.remove()
      }
    }
    const ro = new ResizeObserver(() => { if (!cleanup) start() })
    ro.observe(mount); start()
    return () => {
      ro.disconnect()
      if (animId) cancelAnimationFrame(animId)
      if (cleanup) cleanup()
      const c = mount.querySelector('canvas'); if (c) c.remove()
    }
  }, [])
  return mountRef
}

// ─── Hero Particles Scene ─────────────────────────────────────────
function HeroScene() {
  const ref = useThreeScene((canvas, w, h, setAnim) => {
    const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true })
    renderer.setSize(w, h)
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
    const scene = new THREE.Scene()
    const camera = new THREE.PerspectiveCamera(60, w / h, 0.1, 100)
    camera.position.z = 5

    const count = 1800
    const positions = new Float32Array(count * 3)
    const colors = new Float32Array(count * 3)
    for (let i = 0; i < count; i++) {
      positions[i * 3]     = (Math.random() - 0.5) * 16
      positions[i * 3 + 1] = (Math.random() - 0.5) * 9
      positions[i * 3 + 2] = (Math.random() - 0.5) * 4
      const r = 0.7 + Math.random() * 0.3
      colors[i * 3]     = r * 0.78
      colors[i * 3 + 1] = r * 0.56
      colors[i * 3 + 2] = r * 0.18
    }
    const geo = new THREE.BufferGeometry()
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3))
    geo.setAttribute('color',    new THREE.BufferAttribute(colors, 3))
    const mat = new THREE.PointsMaterial({ size: 0.04, vertexColors: true, transparent: true, opacity: 0.7 })
    const pts = new THREE.Points(geo, mat)
    scene.add(pts)

    let mx = 0, my = 0
    const onMouseMove = e => {
      mx = (e.clientX / window.innerWidth - 0.5) * 0.6
      my = (e.clientY / window.innerHeight - 0.5) * 0.4
    }
    window.addEventListener('mousemove', onMouseMove)

    let t = 0
    const tick = () => {
      const id = requestAnimationFrame(tick)
      setAnim(id)
      t += 0.0008
      pts.rotation.y = t * 0.12 + mx * 0.3
      pts.rotation.x = my * 0.2
      const pos = geo.attributes.position.array
      for (let i = 0; i < count; i++) {
        pos[i * 3 + 1] += 0.0006
        if (pos[i * 3 + 1] > 4.5) pos[i * 3 + 1] = -4.5
      }
      geo.attributes.position.needsUpdate = true
      renderer.render(scene, camera)
    }
    tick()

    return () => {
      window.removeEventListener('mousemove', onMouseMove)
      geo.dispose(); mat.dispose(); renderer.dispose()
    }
  })
  return <div ref={ref} style={{ position: 'absolute', inset: 0 }} />
}

